import { convertToModelMessages, streamText, type UIMessage } from "ai";

import { getSelectedModel } from "@/lib/ai/models";
import { chatSystemPrompt } from "@/lib/ai/prompts";

export const maxDuration = 60;

type ChatRequest = {
  messages?: UIMessage[];
  message?: UIMessage;
  model?: string;
};

export async function POST(request: Request) {
  let body: ChatRequest;

  try {
    body = (await request.json()) as ChatRequest;
  } catch {
    return Response.json({ error: "Invalid JSON body" }, { status: 400 });
  }

  const messages = body.messages ?? (body.message ? [body.message] : []);

  try {
    const result = streamText({
      model: getSelectedModel(body.model),
      system: chatSystemPrompt,
      messages: convertToModelMessages(messages),
    });

    return result.toUIMessageStreamResponse();
  } catch (error) {
    return Response.json(
      { error: error instanceof Error ? error.message : "Unable to start chat stream." },
      { status: 400 },
    );
  }
}

"use client";

import { useChat } from "@ai-sdk/react";
import { DefaultChatTransport } from "ai";
import { ArrowUpIcon, SquareIcon } from "lucide-react";
import { useMemo, useState } from "react";

export function ChatBox() {
  const [input, setInput] = useState("");
  const transport = useMemo(() => new DefaultChatTransport({ api: "/api/ai/chat" }), []);
  const { messages, sendMessage, status, stop } = useChat({ transport });
  const running = status === "submitted" || status === "streaming";

  function submit() {
    const text = input.trim();
    if (!text || running) return;
    sendMessage({ text });
    setInput("");
  }

  return (
    <div className="flex flex-col gap-4 rounded-lg border p-4">
      <div className="flex flex-col gap-3">
        {messages.map((message) => (
          <div key={message.id} className="rounded-md bg-muted p-3 text-sm">
            <div className="mb-1 font-medium">{message.role}</div>
            {message.parts.map((part, index) =>
              part.type === "text" ? <p key={index}>{part.text}</p> : null,
            )}
          </div>
        ))}
      </div>
      <div className="flex gap-2">
        <textarea
          className="min-h-24 flex-1 rounded-md border bg-background p-3 text-sm"
          value={input}
          onChange={(event) => setInput(event.target.value)}
          placeholder="Ask a question..."
        />
        {running ? (
          <button className="rounded-md border px-3" type="button" onClick={stop}>
            <SquareIcon />
          </button>
        ) : (
          <button className="rounded-md border px-3" type="button" onClick={submit}>
            <ArrowUpIcon />
          </button>
        )}
      </div>
    </div>
  );
}

export const DEFAULT_AI_MODEL = process.env.AI_GATEWAY_MODEL;

export function getSelectedModel(model?: string) {
  const selected = model || DEFAULT_AI_MODEL;
  if (!selected) {
    throw new Error("AI_GATEWAY_MODEL is not set.");
  }
  return selected;
}
